import { getDisabledAgentsForStage } from '../services/model-router';

/** All agent names registered by FlowDeck. */
export const AGENT_NAMES: readonly string[] = [
  'orchestrator',
  'default-executor',
  'planner',
  'backend-coder',
  'frontend-coder',
  'devops',
